SELECT /*boardMapper.countBylistProdCommend  */
    COUNT(*)
FROM
    NMCP_BOARD_BAS
WHERE 1=1



            AND BOARD_CTG_SEQ IN

                #{item}



            AND BOARD_CTG_SEQ = #{boardCtgSeq}




        AND SBST_CTG = #{sbstCtg}


        AND BOARD_SUBJECT LIKE '%' || #{boardSubject} ||'%'


        AND VIEW_YN  = #{viewYn}


        AND ( UPPER(fnHTMLtoTEXT(BOARD_SUBJECT)) LIKE '%' || UPPER(#{searchNm}) || '%' || '%' ESCAPE '!'
              OR UPPER(fnHTMLtoTEXT(BOARD_CONTENTS)) LIKE '%' || UPPER(#{searchNm}) || '%' || '%' ESCAPE '!')

SELECT /*boardMapper.listBoardBas */ BOARD_CTG_SEQ --카테고리일련번호 , SBST_CTG --게시물카테고리 , BOARD_SEQ --게시물인련번호 , BOARD_SUBJECT --게시물제목 , VIEW_YN --노출여부 , NOTI_YN --공지여부 , BOARD_WRITER_NM --작성자 , BOARD_WRITE_DT --작성일 , BOARD_ATT_YN --첨부여부 , BOARD_HIT_CNT --조회수 , CRET_ID --생성자아이디 , AMD_ID --수정자아이디 , CRET_DT --생성일시 , AMD_DT --수정일시 FROM NMCP_BOARD_BAS WHERE 1=1
AND BOARD_CTG_SEQ IN
#{item}
AND BOARD_CTG_SEQ = #{boardCtgSeq}
AND SBST_CTG = #{sbstCtg}
AND BOARD_SUBJECT LIKE '%' || #{boardSubject} ||'%'
AND VIEW_YN = #{viewYn}
AND ( UPPER(fnHTMLtoTEXT(BOARD_SUBJECT)) LIKE '%' || UPPER(#{searchNm}) || '%' || '%' ESCAPE '!' OR UPPER(fnHTMLtoTEXT(BOARD_CONTENTS)) LIKE '%' || UPPER(#{searchNm}) || '%' || '%' ESCAPE '!')
ORDER BY CRET_DT DESC, BOARD_SEQ DESC

SELECT COUNT(BOARD_SEQ) FROM NMCP_BOARD_BAS WHERE BOARD_CTG_SEQ = #{boardCtgSeq}
AND BOARD_WRITER_NM = #{boardWriterNm}
AND BOARD_SEQ NOT IN (SELECT board_seq FROM ( SELECT ROWNUM AS RNUM, A.BOARD_SEQ FROM ( SELECT BOARD_SEQ, BOARD_CTG_SEQ, SBST_CTG, ( SELECT DTL_CD_NM FROM nmcp_cd_dtl WHERE CD_GROUP_ID = 'FAQB' AND DTL_CD = SBST_CTG ) AS SBST_CTG_NM, BOARD_SUBJECT, VIEW_YN, NOTI_YN, BOARD_WRITER_NM, TO_CHAR (BOARD_WRITE_DT, 'YYYY.MM.DD') AS BOARD_WRITE_DT, BOARD_ATT_YN, BOARD_HIT_CNT FROM NMCP_BOARD_BAS WHERE BOARD_CTG_SEQ = #{boardCtgSeq} AND NOTI_YN = 'Y' ORDER BY CRET_DT DESC,BOARD_SEQ DESC ) A ) WHERE RNUM >= 1 AND RNUM <= 5)
AND ( BOARD_SUBJECT LIKE '%' || #{searchNm} ||'%' OR BOARD_CONTENTS LIKE '%' || #{searchNm} ||'%')
AND BOARD_SUBJECT LIKE '%' || #{searchNm} || '%'
AND BOARD_CONTENTS LIKE '%' || #{searchNm} ||'%'
AND BOARD_SUBJECT LIKE '%' || #{searchNm} ||'%'
AND SBST_CTG = #{sbstCtg}

SELECT RNUM ,RNUM_SHOW ,BOARD_SEQ ,BOARD_CTG_SEQ ,SBST_CTG ,CRET_DT ,SBST_CTG_NM ,BOARD_SUBJECT ,VIEW_YN ,NOTI_YN ,BOARD_WRITER_NM ,BOARD_WRITE_DT ,BOARD_WRITE_TM ,BOARD_ATT_YN ,BOARD_HIT_CNT FROM ( SELECT ROW_NUMBER() OVER (ORDER BY A.CRET_DT DESC, A.BOARD_SEQ DESC) AS RNUM , ROW_NUMBER() OVER (ORDER BY A.CRET_DT , A.BOARD_SEQ ASC) AS RNUM_SHOW , A.BOARD_SEQ , A.BOARD_CTG_SEQ , A.SBST_CTG , A.CRET_DT , A.SBST_CTG_NM , A.BOARD_SUBJECT , A.VIEW_YN , A.NOTI_YN , A.BOARD_WRITER_NM ,A.BOARD_WRITE_DT ,A.BOARD_WRITE_TM ,A.BOARD_ATT_YN ,A.BOARD_HIT_CNT FROM ( SELECT BOARD_SEQ, BOARD_CTG_SEQ, SBST_CTG, CRET_DT, (SELECT DTL_CD_NM FROM nmcp_cd_dtl WHERE CD_GROUP_ID = 'FAQB' AND DTL_CD = SBST_CTG ) AS SBST_CTG_NM, BOARD_SUBJECT, VIEW_YN, NOTI_YN, BOARD_WRITER_NM, TO_CHAR(BOARD_WRITE_DT, 'YYYY.MM.DD') AS BOARD_WRITE_DT, TO_CHAR(BOARD_WRITE_DT, 'HH:MM') AS BOARD_WRITE_TM, BOARD_ATT_YN, BOARD_HIT_CNT FROM NMCP_BOARD_BAS WHERE BOARD_CTG_SEQ = #{boardCtgSeq}
AND BOARD_WRITER_NM = #{boardWriterNm}
AND NOTI_YN = #{notiYn}
AND BOARD_SEQ NOT IN (SELECT board_seq FROM (SELECT ROWNUM AS RNUM, A.BOARD_SEQ FROM ( SELECT BOARD_SEQ, BOARD_CTG_SEQ, SBST_CTG, (SELECT DTL_CD_NM FROM nmcp_cd_dtl WHERE CD_GROUP_ID = 'FAQB' AND DTL_CD = SBST_CTG) AS SBST_CTG_NM, BOARD_SUBJECT, VIEW_YN, NOTI_YN, BOARD_WRITER_NM, TO_CHAR (BOARD_WRITE_DT, 'YYYY.MM.DD') AS BOARD_WRITE_DT, BOARD_ATT_YN, BOARD_HIT_CNT FROM NMCP_BOARD_BAS WHERE BOARD_CTG_SEQ = 51 AND NOTI_YN = 'Y' ORDER BY CRET_DT DESC, BOARD_SEQ DESC) A) WHERE RNUM >= 1 AND RNUM <= 5)
AND ( BOARD_SUBJECT LIKE '%' || #{searchNm} ||'%' OR BOARD_CONTENTS LIKE '%' || #{searchNm} ||'%')
AND BOARD_SUBJECT LIKE '%' || #{searchNm} || '%'
AND BOARD_CONTENTS LIKE '%' || #{searchNm} ||'%'
AND BOARD_SUBJECT LIKE '%' || #{searchNm} ||'%'
AND SBST_CTG = #{sbstCtg}
AND VIEW_YN = #{viewYn}
ORDER BY CRET_DT DESC, BOARD_SEQ DESC ) A ) WHERE RNUM > (#{pagingStartNo}-1) * #{pagingSize} AND RNUM <= #{pagingEndNo} * #{pagingStartNo}

SELECT RNUM ,RNUM_SHOW ,BOARD_SEQ ,BOARD_CTG_SEQ ,SBST_CTG ,CRET_DT ,BOARD_SUBJECT ,VIEW_YN ,NOTI_YN ,BOARD_WRITER_NM ,BOARD_WRITE_DT ,BOARD_ATT_YN ,BOARD_HIT_CNT ,ATT_SEQ ,FILE_PATH_NM ,FILE_TYPE ,DOWNLOAD_COUNT FROM ( SELECT ROW_NUMBER() OVER (ORDER BY A.CRET_DT DESC,A.BOARD_SEQ DESC) AS RNUM , ROW_NUMBER() OVER (ORDER BY A.CRET_DT , A.BOARD_SEQ ASC) AS RNUM_SHOW , A.BOARD_SEQ , A.BOARD_CTG_SEQ , A.SBST_CTG , A.CRET_DT , A.BOARD_SUBJECT , A.VIEW_YN , A.NOTI_YN , A.BOARD_WRITER_NM , A.BOARD_WRITE_DT , A.BOARD_ATT_YN , A.BOARD_HIT_CNT , A.ATT_SEQ , A.FILE_PATH_NM , A.FILE_TYPE , A.DOWNLOAD_COUNT FROM ( SELECT A.BOARD_SEQ, A.BOARD_CTG_SEQ, A.SBST_CTG, A.CRET_DT, A.BOARD_SUBJECT, A.VIEW_YN, A.NOTI_YN, A.BOARD_WRITER_NM, TO_CHAR(A.BOARD_WRITE_DT, 'YYYY.MM.DD') AS BOARD_WRITE_DT, A.BOARD_ATT_YN, A.BOARD_HIT_CNT, B.ATT_SEQ, REPLACE(B.FILE_PATH_NM, '\', '/') AS FILE_PATH_NM, B.FILE_TYPE, B.DOWNLOAD_COUNT FROM NMCP_BOARD_BAS A , ( SELECT AA.ATT_SEQ, AA.FILE_PATH_NM,AA.FILE_TYPE,AA.BOARD_SEQ,AA.DOWNLOAD_COUNT FROM NMCP_BOARD_ATT_DTL AA , ( SELECT MAX(ATT_SEQ) AS ATT_SEQ,BOARD_SEQ FROM NMCP_BOARD_ATT_DTL GROUP BY BOARD_SEQ ) BB WHERE AA.ATT_SEQ = BB.ATT_SEQ AND AA.BOARD_SEQ = BB.BOARD_SEQ ) B WHERE BOARD_CTG_SEQ = #{boardCtgSeq} AND A.BOARD_SEQ = B.BOARD_SEQ(+)
AND BOARD_WRITER_NM = #{boardWriterNm}
AND NOTI_YN = #{notiYn}
AND BOARD_SUBJECT LIKE '%' || #{searchNm} || '%'
AND BOARD_CONTENTS LIKE '%' || #{searchNm} ||'%'
AND BOARD_SUBJECT LIKE '%' || #{searchNm} ||'%'
AND SBST_CTG = #{sbstCtg}
AND A.BOARD_SEQ NOT IN (SELECT board_seq FROM (SELECT ROWNUM AS RNUM, AA.BOARD_SEQ FROM ( SELECT BOARD_SEQ, BOARD_CTG_SEQ, SBST_CTG, (SELECT DTL_CD_NM FROM nmcp_cd_dtl WHERE CD_GROUP_ID = 'FAQB' AND DTL_CD = SBST_CTG) AS SBST_CTG_NM, BOARD_SUBJECT, VIEW_YN, NOTI_YN, BOARD_WRITER_NM, TO_CHAR (BOARD_WRITE_DT, 'YYYY.MM.DD') AS BOARD_WRITE_DT, BOARD_ATT_YN, BOARD_HIT_CNT FROM NMCP_BOARD_BAS WHERE BOARD_CTG_SEQ = 53 AND NOTI_YN = 'Y' ORDER BY CRET_DT DESC, BOARD_SEQ DESC) AA) WHERE RNUM >= 1 AND RNUM <= 5)
ORDER BY A.CRET_DT DESC, A.BOARD_SEQ DESC ) A ) WHERE RNUM > (#{pagingStartNo}-1) * #{pagingSize} AND RNUM <= #{pagingEndNo} * #{pagingStartNo}

mapper.update:
UPDATE NMCP_BOARD_BAS SET
BOARD_CTG_SEQ = #{boardCtgSeq},
SBST_CTG = #{sbstCtg}, BOARD_SUBJECT = #{boardSubject}, VIEW_YN = #{viewYn}, NOTI_YN = #{notiYn}, BOARD_CONTENTS = #{boardContents}, BOARD_WRITER_NM = #{boardWriterNm}, BOARD_ATT_YN = #{boardAttYn}, AMD_ID = #{amdId}, AMD_DT = SYSDATE WHERE BOARD_SEQ = #{boardSeq}
